mapper.select:
SELECT vacuum_raw_metrics_id AS vacuumRawMetricsId, database_id AS databaseId, collected_at AS collectedAt, blocker_xmin_horizon AS blockerXminHorizon, tuples_deleted AS tuplesDeleted, elapsed_seconds AS elapsedSeconds FROM vacuum_raw_metrics WHERE collected_at BETWEEN #{startTime} AND #{endTime}
AND database_id = #{databaseId}
ORDER BY collected_at ASC

SELECT vacuum_raw_metrics_id AS vacuumRawMetricsId, database_id AS databaseId, collected_at AS collectedAt, blocker_xmin_horizon AS blockerXminHorizon, tuples_deleted AS tuplesDeleted, elapsed_seconds AS elapsedSeconds FROM vacuum_raw_metrics WHERE collected_at >= #{since}
AND database_id = #{databaseId}
ORDER BY collected_at DESC LIMIT 1000

SELECT vacuum_raw_metrics_id AS vacuumRawMetricsId, database_id AS databaseId, collected_at AS collectedAt, blocker_xmin_horizon AS blockerXminHorizon FROM vacuum_raw_metrics WHERE blocker_xmin_horizon IS NOT NULL
AND database_id = #{databaseId}
ORDER BY collected_at DESC LIMIT 100

SELECT vacuum_raw_metrics_id AS vacuumRawMetricsId, database_id AS databaseId, n_dead_tup AS nDeadTup, n_live_tup AS nLiveTup FROM vacuum_raw_metrics WHERE n_dead_tup > #{threshold}
AND database_id = #{databaseId}
ORDER BY n_dead_tup DESC LIMIT 100

SELECT database_id AS databaseId, collected_at AS collectedAt, max_dead_tuples AS bloatBytes, CASE WHEN total_dead_tuples > 0 THEN max_dead_tuples::NUMERIC / total_dead_tuples ELSE 0 END AS bloatRatio FROM ${aggTable} WHERE collected_at >= #{startDate}
AND database_id = #{databaseId}
ORDER BY collected_at ASC

WITH latest_per_db AS ( SELECT DISTINCT ON (database_id, instance_id) database_id, instance_id, CASE WHEN total_dead_tuples > 0 THEN max_dead_tuples::NUMERIC / total_dead_tuples ELSE 0 END as bloat_ratio, collected_at FROM ${aggTable} WHERE collected_at >= #{since}
AND database_id = #{databaseId}
ORDER BY database_id, instance_id, collected_at DESC ) SELECT CASE WHEN bloat_ratio < 0.05 THEN '0-5%' WHEN bloat_ratio < 0.10 THEN '5-10%' WHEN bloat_ratio < 0.15 THEN '10-15%' WHEN bloat_ratio < 0.20 THEN '15-20%' WHEN bloat_ratio < 0.30 THEN '20-30%' ELSE '30%+' END as range, COUNT(*) as count FROM latest_per_db WHERE bloat_ratio > 0 GROUP BY range ORDER BY MIN(bloat_ratio)

WITH latest_per_db AS (
SELECT DISTINCT ON (database_id, instance_id)
database_id,
instance_id,
max_dead_tuples as bloat_estimate,
collected_at
FROM ${aggTable}
WHERE collected_at >= #{since}

    AND database_id = #{databaseId}

ORDER BY database_id, instance_id, collected_at DESC
)
SELECT COALESCE(SUM(bloat_estimate), 0)
FROM latest_per_db

WITH latest_per_db AS ( SELECT DISTINCT ON (database_id, instance_id) database_id, instance_id, CASE WHEN total_dead_tuples > 0 THEN max_dead_tuples::NUMERIC / total_dead_tuples ELSE 0 END as bloat_ratio, collected_at FROM ${aggTable} WHERE collected_at >= #{since}
AND database_id = #{databaseId}
ORDER BY database_id, instance_id, collected_at DESC ) SELECT COUNT(*) FROM latest_per_db WHERE bloat_ratio >= 0.15

WITH daily_agg AS ( SELECT database_id, DATE_TRUNC('day', collected_at) as day, AVG(max_dead_tuples) as avg_bloat_bytes, AVG( CASE WHEN total_dead_tuples > 0 THEN max_dead_tuples::NUMERIC / total_dead_tuples ELSE 0 END ) as avg_bloat_ratio, MAX(collected_at) as collected_at FROM ${aggTable} WHERE collected_at >= #{startDate}
AND database_id = #{databaseId}
GROUP BY database_id, DATE_TRUNC('day', collected_at) ) SELECT database_id AS databaseId, collected_at AS collectedAt, CAST(avg_bloat_bytes AS BIGINT) AS bloatBytes, avg_bloat_ratio AS bloatRatio FROM daily_agg ORDER BY collected_at ASC

WITH latest_per_db AS ( SELECT DISTINCT ON (database_id, instance_id) database_id, instance_id, 'db_' || database_id::TEXT || '_inst_' || instance_id::TEXT AS table_name, LEAST( (total_dead_tuples::NUMERIC / 200000000) * 100, 100 ) AS wraparound_progress_pct, collected_at FROM ${aggTable} WHERE collected_at >= NOW() - INTERVAL '1 day'
AND database_id = #{databaseId}
ORDER BY database_id, instance_id, collected_at DESC ) SELECT database_id AS databaseId, table_name AS tableName, wraparound_progress_pct AS wraparoundProgressPct FROM latest_per_db WHERE wraparound_progress_pct > #{threshold} ORDER BY wraparound_progress_pct DESC LIMIT 100

WITH latest AS ( SELECT database_id, instance_id, MAX(collected_at) as max_collected_at FROM ${aggTable}
WHERE database_id = #{databaseId}
GROUP BY database_id, instance_id ) SELECT v.database_id AS databaseId, 'db_' || v.database_id::TEXT || '_inst_' || v.instance_id::TEXT AS tableName, v.collected_at AS collectedAt, v.max_dead_tuples AS bloatBytes, CASE WHEN v.total_dead_tuples > 0 THEN v.max_dead_tuples::NUMERIC / v.total_dead_tuples ELSE 0 END AS bloatRatio FROM ${aggTable} v INNER JOIN latest ON v.database_id = latest.database_id AND v.instance_id = latest.instance_id AND v.collected_at = latest.max_collected_at ORDER BY bloat_ratio DESC NULLS LAST LIMIT 100
